/*
 * Boolean Algebra Theorem Verification System
 * Demonstrates verification of Boolean algebra theorems using C
 */

#include <stdio.h>
#include <stdlib.h>
#include <math.h>

/* Boolean operation functions */
int NOT(int a) {
 return (a == 0) ? 1 : 0;
}

int AND(int a, int b) {
 return (a == 1 && b == 1) ? 1 : 0;
}

int OR(int a, int b) {
 return (a == 1 || b == 1) ? 1 : 0;
}

int NAND(int a, int b) {
 return NOT(AND(a, b));
}

int NOR(int a, int b) {
 return NOT(OR(a, b));
}

/* Theorem verification functions */
void verifyDeMorgansFirst() {
 printf("\n=== De Morgan's First Theorem: (A + B)' = A' · B' ===\n");
 printf(" A | B | (A+B)' | A'·B' | Verified\n");
 printf("-----------------------------------\n");

 int A, B, lhs, rhs;
 int verified = 1;

 for (A = 0; A <= 1; A++) {
 for (B = 0; B <= 1; B++) {
 lhs = NOT(OR(A, B)); /* (A + B)' */
 rhs = AND(NOT(A), NOT(B)); /* A' · B' */

 printf(" %d | %d | %d | %d | %c\n", 
 A, B, lhs, rhs, (lhs == rhs) ? '✓' : '✗');

 if (lhs != rhs) verified = 0;
 }
 }
 printf("Result: %s\n", verified ? "VERIFIED ✓" : "FAILED ✗");
}

void verifyDeMorgansSecond() {
 printf("\n=== De Morgan's Second Theorem: (A · B)' = A' + B' ===\n");
 printf(" A | B | (A·B)' | A'+B' | Verified\n");
 printf("-----------------------------------\n");

 int A, B, lhs, rhs;
 int verified = 1;

 for (A = 0; A <= 1; A++) {
 for (B = 0; B <= 1; B++) {
 lhs = NOT(AND(A, B)); /* (A · B)' */
 rhs = OR(NOT(A), NOT(B)); /* A' + B' */

 printf(" %d | %d | %d | %d | %c\n", 
 A, B, lhs, rhs, (lhs == rhs) ? '✓' : '✗');

 if (lhs != rhs) verified = 0;
 }
 }
 printf("Result: %s\n", verified ? "VERIFIED ✓" : "FAILED ✗");
}

void verifyAbsorptionLaws() {
 printf("\n=== Absorption Laws ===\n");

 /* First Absorption: A + (A · B) = A */
 printf("\nFirst Absorption: A + (A · B) = A\n");
 printf(" A | B | A+(A·B) | A | Verified\n");
 printf("---------------------------------\n");

 int A, B, lhs, rhs;

 for (A = 0; A <= 1; A++) {
 for (B = 0; B <= 1; B++) {
 lhs = OR(A, AND(A, B)); /* A + (A · B) */
 rhs = A;
 printf(" %d | %d | %d | %d | %c\n", 
 A, B, lhs, rhs, (lhs == rhs) ? '✓' : '✗');
 }
 }

 /* Second Absorption: A · (A + B) = A */
 printf("\nSecond Absorption: A · (A + B) = A\n");
 printf(" A | B | A·(A+B) | A | Verified\n");
 printf("---------------------------------\n");

 for (A = 0; A <= 1; A++) {
 for (B = 0; B <= 1; B++) {
 lhs = AND(A, OR(A, B)); /* A · (A + B) */
 rhs = A;
 printf(" %d | %d | %d | %d | %c\n", 
 A, B, lhs, rhs, (lhs == rhs) ? '✓' : '✗');
 }
 }
}

void verifyDistributiveLaw() {
 printf("\n=== Distributive Law: A · (B + C) = (A·B) + (A·C) ===\n");
 printf("A | B | C | LHS | RHS | Verified\n");
 printf("-------------------------------\n");

 int A, B, C, lhs, rhs;
 int verified = 1;

 for (A = 0; A <= 1; A++) {
 for (B = 0; B <= 1; B++) {
 for (C = 0; C <= 1; C++) {
 lhs = AND(A, OR(B, C)); /* A · (B + C) */
 rhs = OR(AND(A, B), AND(A, C)); /* (A·B) + (A·C) */

 printf(" %d | %d | %d | %d | %d | %c\n", 
 A, B, C, lhs, rhs, (lhs == rhs) ? '✓' : '✗');

 if (lhs != rhs) verified = 0;
 }
 }
 }
 printf("Result: %s\n", verified ? "VERIFIED ✓" : "FAILED ✗");
}

void verifyConsensusTheorem() {
 printf("\n=== Consensus Theorem: (A·B)+(A'·C)+(B·C) = (A·B)+(A'·C) ===\n");
 printf("A | B | C | LHS | RHS | Verified\n");
 printf("-------------------------------\n");

 int A, B, C, lhs, rhs;
 int verified = 1;

 for (A = 0; A <= 1; A++) {
 for (B = 0; B <= 1; B++) {
 for (C = 0; C <= 1; C++) {
 /* LHS: (A·B) + (A'·C) + (B·C) */
 lhs = OR(OR(AND(A, B), AND(NOT(A), C)), AND(B, C));
 /* RHS: (A·B) + (A'·C) */
 rhs = OR(AND(A, B), AND(NOT(A), C));

 printf(" %d | %d | %d | %d | %d | %c\n", 
 A, B, C, lhs, rhs, (lhs == rhs) ? '✓' : '✗');

 if (lhs != rhs) verified = 0;
 }
 }
 }
 printf("Note: Term (B·C) is REDUNDANT and can be eliminated!\n");
 printf("Result: %s\n", verified ? "VERIFIED ✓" : "FAILED ✗");
}

void demonstrateSimplification() {
 printf("\n=== Expression Simplification Demo ===\n");
 printf("Problem: Simplify X + (X' · Y)\n\n");
 printf("Step 1: Apply Distributive Law\n");
 printf(" = (X + X') · (X + Y)\n\n");
 printf("Step 2: Apply Complement Law (X + X' = 1)\n");
 printf(" = 1 · (X + Y)\n\n");
 printf("Step 3: Apply Identity Law (1 · A = A)\n");
 printf(" = X + Y\n\n");

 printf("Verification:\n");
 printf(" X | Y | X+(X'·Y) | X+Y | Verified\n");
 printf("-------------------------------\n");

 int X, Y, original, simplified;

 for (X = 0; X <= 1; X++) {
 for (Y = 0; Y <= 1; Y++) {
 original = OR(X, AND(NOT(X), Y)); /* X + (X' · Y) */
 simplified = OR(X, Y); /* X + Y */

 printf(" %d | %d | %d | %d | %c\n", 
 X, Y, original, simplified, 
 (original == simplified) ? '✓' : '✗');
 }
 }
}

int main() {
 printf("========================================\n");
 printf(" BOOLEAN ALGEBRA THEOREM VERIFICATION \n");
 printf("========================================\n");

 verifyDeMorgansFirst();
 verifyDeMorgansSecond();
 verifyAbsorptionLaws();
 verifyDistributiveLaw();
 verifyConsensusTheorem();
 demonstrateSimplification();

 printf("\n========================================\n");
 printf(" All theorems verified using truth tables\n");
 printf(" This demonstrates the fundamental laws\n");
 printf(" of Boolean algebra used in digital\n");
 printf(" circuit design and optimization.\n");
 printf("========================================\n");

 return 0;
}
